import {
  CalendarToday,
  LocationSearching,
  MailOutline,
  PermIdentity,
  PhoneAndroid,
  Publish,
} from "@material-ui/icons";
import { Link, useLocation } from "react-router-dom";
import { useSelector } from 'react-redux';
import "./order.css";
import {format} from 'timeago.js';

const Order = () => {
  const location = useLocation();
  const orderId = location.pathname.split("/")[2];

  const order = useSelector((state) => 
    state.order.orders.find(order => order._id === orderId)
  );

  const handleUpdateOrder = () => {

  }

  return (
    <div className="order">
        <h1 className="orderTitle">Order ID {order._id}</h1>
        <div className="personalInfo">
            <div className="left">
                <h2>Personal Information</h2>
                <div className="infoLine">
                    <p className="infoLineTitle">User ID: <span> </span></p>
                    <p>{order.userId}</p>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle">User Email: <span> </span></p>
                    <p>{order.email}</p>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle">Order Status: <span> </span></p>
                    <p>{order.status}</p>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle">Created At: <span> </span></p>
                    <p>{order.createdAt}</p>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle">Updated At: <span> </span></p>
                    <p>{order.updatedAt}</p>
                </div>
            </div>
            <div className="right">
                <h2 className="address">Address</h2>
            </div>
        </div>
    </div>
  );
};

export default Order;
